#include <stdio.h>
#include <stdlib.h>
int cmp(const void *a, const void *b){return (*(int*)a)-(*(int*)b);} 
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int *a = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d",&a[i]);
        qsort(a,N,sizeof(int),cmp);
        int k = N/2;
        if(a[k-1] >= a[k]){
            printf("-1\n");
            free(a);
            continue;
        }
        // build answer
        int *ans = (int*)malloc(N*sizeof(int));
        int idx=0;
        int i=0,j=0; // i for large, j for small
        int largeStart = k; // first index of large part
        int smallEnd = k; // exclusive
        while(idx<N){
            if(largeStart < N){ ans[idx++] = a[largeStart++]; }
            if(j < smallEnd){ ans[idx++] = a[j++]; }
        }
        for(int p=0;p<N;p++){
            if(p) printf(" ");
            printf("%d",ans[p]);
        }
        printf("\n");
        free(a); free(ans);
    }
    return 0;
}

