#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<long long> a(N);
        for(int i=0;i<N;i++) cin>>a[i];
        sort(a.begin(), a.end());
        int k = N/2;
        if(a[k-1] >= a[k]){
            cout<<-1<<"\n";
            continue;
        }
        vector<long long> ans; ans.reserve(N);
        int i=k, j=0; // i for large, j for small
        while((int)ans.size()<N){
            if(i<N) ans.push_back(a[i++]);
            if(j<k) ans.push_back(a[j++]);
        }
        for(int i=0;i<N;i++){
            if(i) cout<<' ';
            cout<<ans[i];
        }
        cout<<"\n";
    }
    return 0;
}

