#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        a.sort()
        k = N // 2
        if a[k-1] >= a[k]:
            out_lines.append('-1')
            continue
        ans = []
        i, j = k, 0
        while len(ans) < N:
            if i < N:
                ans.append(a[i])
                i += 1
            if j < k:
                ans.append(a[j])
                j += 1
        out_lines.append(' '.join(map(str, ans)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

